  .BYTE $FF, $0E, $0A, $23, $FF, $02, $0B, $0A, $FF, $08, $0B, $3A, $FF, $0E, $12, $46 
  .BYTE $FE, $01, $01, $07, $5A, $FF, $01, $05, $6D, $05, $67, $03, $71, $FF, $02, $04 
