  .BYTE $9D, $FE, $04, $04, $16, $99, $07, $6E, $FC, $00, $00, $40, $04, $04, $C0, $FE 
  .BYTE $54, $05, $03, $C7, $FE, $50, $55, $03, $CB, $FB, $50, $55, $55, $05, $55, $04 
  .BYTE $D8, $06, $D7, $FF, $45, $05, $DE, $07, $E8, $FE, $28, $08, $00 

